mapper.select:
SELECT GATE_CD , USER_TYPE , USER_ID , USER_NM AS USER_NM , COMPANY_CD , COMPANY_NM , DEPT_CD , DEPT_NM , TEL_NUM AS TEL_NUM , POSITION_NM , CELL_NUM AS CELL_NUM , EMAIL AS EMAIL FROM ( SELECT A.GATE_CD , A.USER_TYPE , A.USER_ID , A.USER_NM , A.COMPANY_CD , B.BUYER_NM AS COMPANY_NM , A.DEPT_CD , C.DEPT_NM , A.TEL_NUM , A.POSITION_NM , A.CELL_NUM , A.EMAIL FROM STOCUSER A LEFT OUTER JOIN STOCOGCM B ON (A.GATE_CD = B.GATE_CD AND A.COMPANY_CD = B.BUYER_CD) LEFT OUTER JOIN STOCOGDP C ON (A.GATE_CD = C.GATE_CD AND A.COMPANY_CD = C.BUYER_CD AND A.DEPT_CD = C.DEPT_CD)
UNION ALL
SELECT A.GATE_CD , A.USER_TYPE , A.USER_ID , A.USER_NM , A.COMPANY_CD , (CASE A.USER_TYPE WHEN 'B' THEN B.CUST_NM WHEN 'S' THEN C.VENDOR_NM END) AS COMPANY_NM , A.DEPT_CD , A.DEPT_NM , A.TEL_NUM , A.POSITION_NM , A.CELL_NUM , A.EMAIL FROM STOCCVUR A LEFT OUTER JOIN STOCCUST B ON (A.GATE_CD = B.GATE_CD AND A.COMPANY_CD = B.CUST_CD) LEFT OUTER JOIN STOCVNGL C ON (A.GATE_CD = C.GATE_CD AND A.COMPANY_CD = C.VENDOR_CD) ) AA WHERE AA.GATE_CD = #{ses.gateCd} AND AA.USER_TYPE = #{USER_TYPE} AND AA.USER_ID = #{USER_ID}
